_FN = 'layer_norm_custom'

class ModelNew(torch.nn.Module):
    def __init__(self, normalized_shape):
        super(ModelNew, self).__init__()
        self.normalized_shape = tuple(normalized_shape)
        self.weight = torch.nn.Parameter(torch.ones(self.normalized_shape, dtype=torch.float))
        self.bias = torch.nn.Parameter(torch.zeros(self.normalized_shape, dtype=torch.float))
        self.eps = 1e-5

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        fn = getattr(custom_ops_lib, _FN)
        return fn(x, self.weight, self.bias, self.eps)
